const err = $input.first().json;

const execution = err.execution || {};
const workflow = execution.workflow || {};
const lastNode = execution.lastNodeExecuted || 'unknown';
const errMsg = err.execution?.error?.message || err.message || 'Unknown error';
const errType = err.execution?.error?.name || 'Error';

return [{
  json: {
    workflow_id: workflow.id || 'unknown',
    workflow_name: workflow.name || 'Unknown Workflow',
    execution_id: String(execution.id || ''),
    node_name: lastNode,
    error_message: errMsg,
    error_type: errType
  }
}];
